package com.assetflow.nexora.entity;
import jakarta.persistence.*; import java.time.*; @Entity @Table(name="users") public class User extends AuditedEntity { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) @Column(name="user_id") public Long id; @Column(name="full_name",nullable=false,length=150) public String fullName; @Column(nullable=false,unique=true,length=150) public String email; @Column(name="password_hash",nullable=false,length=255) public String passwordHash; @Column(name="department_id") public Long departmentId; @Column(name="role_id",nullable=false) public Short roleId; @Column(nullable=false,length=20) public String status="Active"; @Column(name="promoted_by") public Long promotedBy; @Column(name="promoted_at") public OffsetDateTime promotedAt; @Column(name="last_login_at") public OffsetDateTime lastLoginAt; }
